import React, { useState } from 'react';

const FormularioCampesenaCompleto = ({ formData, setFormData }) => {
  const [instructores, setInstructores] = useState([
    {
      tipo: 'Técnico',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      programacion: [] // <-- Array de meses con rangos de fechas
    },
    {
      tipo: 'Empresarial',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      programacion: []
    },
    {
      tipo: 'Popular',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      programacion: []
    }
  ]);

  // ===== FUNCIONES PARA MANEJAR INSTRUCTORES =====

  // Actualizar campos del instructor
  const actualizarCampo = (indexInstructor, campo, valor) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor][campo] = valor;
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Agregar un nuevo mes a un instructor
  const agregarMes = (indexInstructor) => {
    const nuevosInstructores = [...instructores];
    const numMes = nuevosInstructores[indexInstructor].programacion.length + 1;
    
    nuevosInstructores[indexInstructor].programacion.push({
      mes: numMes,
      rangos: [] // Aquí irán los rangos {desde, hasta, hora_inicio, hora_fin}
    });
    
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Agregar un nuevo rango de fechas a un mes específico
  const agregarRango = (indexInstructor, indexMes) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].programacion[indexMes].rangos.push({
      desde: '',
      hasta: '',
      hora_inicio: '08:00',
      hora_fin: '16:00'
    });
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Actualizar un campo de rango específico
  const actualizarRango = (indexInstructor, indexMes, indexRango, campo, valor) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].programacion[indexMes].rangos[indexRango][campo] = valor;
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Eliminar un rango específico
  const eliminarRango = (indexInstructor, indexMes, indexRango) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].programacion[indexMes].rangos.splice(indexRango, 1);
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // Eliminar un mes completo
  const eliminarMes = (indexInstructor, indexMes) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].programacion.splice(indexMes, 1);
    
    // Reordenar los números de mes
    nuevosInstructores[indexInstructor].programacion.forEach((mes, idx) => {
      mes.mes = idx + 1;
    });
    
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  // ===== FUNCIÓN DE VALIDACIÓN =====
  const validarProgramacion = () => {
    const errores = [];

    instructores.forEach((instructor, idx) => {
      // Validar que cada instructor tenga al menos un mes
      if (instructor.programacion.length === 0) {
        errores.push(`Instructor ${instructor.tipo}: Debe agregar al menos un mes de programación`);
      }

      // Validar cada mes
      instructor.programacion.forEach((mes, mIdx) => {
        if (mes.rangos.length === 0) {
          errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: Debe agregar al menos un rango de fechas`);
        }

        // Validar cada rango
        mes.rangos.forEach((rango, rIdx) => {
          if (!rango.desde) {
            errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}, Rango ${rIdx + 1}: La fecha "desde" es obligatoria`);
          }
          if (!rango.hasta) {
            errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}, Rango ${rIdx + 1}: La fecha "hasta" es obligatoria`);
          }

          if (rango.desde && rango.hasta) {
            const fechaDesde = new Date(rango.desde);
            const fechaHasta = new Date(rango.hasta);
            
            if (fechaHasta <= fechaDesde) {
              errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: La fecha "hasta" debe ser posterior a la fecha "desde"`);
            }
          }

          // Validar horarios
          const [hInicio, mInicio] = rango.hora_inicio.split(':').map(Number);
          const [hFin, mFin] = rango.hora_fin.split(':').map(Number);
          const minutosInicio = hInicio * 60 + mInicio;
          const minutosFin = hFin * 60 + mFin;

          if (minutosFin <= minutosInicio) {
            errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: La hora fin debe ser mayor a la hora inicio`);
          }

          if (minutosFin - minutosInicio < 60) {
            errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: La duración mínima es 1 hora`);
          }

          if (minutosFin - minutosInicio > 600) {
            errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: La duración máxima es 10 horas`);
          }

          if (minutosInicio < 6 * 60) {
            errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: La hora inicio no puede ser antes de las 06:00`);
          }
          if (minutosFin > 22 * 60) {
            errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: La hora fin no puede ser después de las 22:00`);
          }
        });

        // Validar que los rangos no se solapen
        if (mes.rangos.length > 1) {
          const rangosOrdenados = [...mes.rangos].sort((a, b) => new Date(a.desde) - new Date(b.desde));
          
          for (let i = 0; i < rangosOrdenados.length - 1; i++) {
            const rangoActual = rangosOrdenados[i];
            const rangoSiguiente = rangosOrdenados[i + 1];
            
            if (new Date(rangoSiguiente.desde) <= new Date(rangoActual.hasta)) {
              errores.push(`Instructor ${instructor.tipo}, Mes ${mes.mes}: Los rangos de fechas no pueden solaparse`);
            }
          }
        }
      });
    });

    return errores;
  };

  return (
    <div style={styles.container}>
      <h3 style={styles.title}>👨‍🏫 Instructores Campesena</h3>
      <p style={styles.subtitle}>Complete los datos de los 3 instructores y su programación por meses</p>
      
      {instructores.map((instructor, idx) => (
        <div key={idx} style={styles.instructorBox}>
          <h4 style={styles.instructorTitle}>
            {instructor.tipo === 'Técnico' && '🔧'}
            {instructor.tipo === 'Empresarial' && '💼'}
            {instructor.tipo === 'Popular' && '👥'} Instructor {instructor.tipo}
          </h4>
          
          {/* ===== DATOS PERSONALES ===== */}
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Tipo ID:</label>
              <select
                value={instructor.tipo_identificacion}
                onChange={(e) => actualizarCampo(idx, 'tipo_identificacion', e.target.value)}
                style={styles.select}
              >
                <option value="CC">CC</option>
                <option value="CE">CE</option>
                <option value="TI">TI</option>
                <option value="PAP">PAP</option>
                <option value="NIT">NIT</option>
              </select>
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Identificación:</label>
              <input
                type="text"
                value={instructor.identificacion}
                onChange={(e) => actualizarCampo(idx, 'identificacion', e.target.value)}
                style={styles.input}
                placeholder="12345678"
              />
            </div>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre completo:</label>
            <input
              type="text"
              value={instructor.nombre}
              onChange={(e) => actualizarCampo(idx, 'nombre', e.target.value)}
              style={styles.input}
              placeholder="Nombre completo"
            />
          </div>

          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Correo:</label>
              <input
                type="email"
                value={instructor.correo}
                onChange={(e) => actualizarCampo(idx, 'correo', e.target.value)}
                style={styles.input}
                placeholder="correo@ejemplo.com"
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Celular:</label>
              <input
                type="tel"
                value={instructor.celular}
                onChange={(e) => actualizarCampo(idx, 'celular', e.target.value)}
                style={styles.input}
                placeholder="3001234567"
              />
            </div>
          </div>

          {/* ===== PROGRAMACIÓN POR MESES ===== */}
          <h5 style={styles.programacionTitle}>📅 Programación por Meses</h5>
          
          {instructor.programacion.map((mes, mIdx) => (
            <div key={mIdx} style={styles.mesBox}>
              <div style={styles.mesHeader}>
                <h6 style={styles.mesTitle}>Mes {mes.mes}</h6>
                <button
                  type="button"
                  onClick={() => eliminarMes(idx, mIdx)}
                  style={styles.removeMesButton}
                  title="Eliminar este mes"
                >
                  ✕ Eliminar mes
                </button>
              </div>

              {/* RANGOS DE FECHAS */}
              {mes.rangos.map((rango, rIdx) => (
                <div key={rIdx} style={styles.rangoBox}>
                  <div style={styles.rangoHeader}>
                    <span style={styles.rangoTitle}>Rango {rIdx + 1}</span>
                    <button
                      type="button"
                      onClick={() => eliminarRango(idx, mIdx, rIdx)}
                      style={styles.removeRangoButton}
                      title="Eliminar este rango"
                    >
                      ✕
                    </button>
                  </div>
                  
                  <div style={styles.row}>
                    <div style={styles.half}>
                      <label style={styles.label}>Desde:</label>
                      <input
                        type="date"
                        value={rango.desde}
                        onChange={(e) => actualizarRango(idx, mIdx, rIdx, 'desde', e.target.value)}
                        style={styles.input}
                      />
                    </div>
                    <div style={styles.half}>
                      <label style={styles.label}>Hasta:</label>
                      <input
                        type="date"
                        value={rango.hasta}
                        onChange={(e) => actualizarRango(idx, mIdx, rIdx, 'hasta', e.target.value)}
                        style={styles.input}
                      />
                    </div>
                  </div>

                  <div style={styles.row}>
                    <div style={styles.half}>
                      <label style={styles.label}>Hora inicio:</label>
                      <input
                        type="time"
                        value={rango.hora_inicio}
                        onChange={(e) => actualizarRango(idx, mIdx, rIdx, 'hora_inicio', e.target.value)}
                        style={styles.input}
                      />
                    </div>
                    <div style={styles.half}>
                      <label style={styles.label}>Hora fin:</label>
                      <input
                        type="time"
                        value={rango.hora_fin}
                        onChange={(e) => actualizarRango(idx, mIdx, rIdx, 'hora_fin', e.target.value)}
                        style={styles.input}
                      />
                    </div>
                  </div>
                </div>
              ))}

              <button
                type="button"
                onClick={() => agregarRango(idx, mIdx)}
                style={styles.addRangoButton}
              >
                + Agregar rango de fechas
              </button>
            </div>
          ))}

          <button
            type="button"
            onClick={() => agregarMes(idx)}
            style={styles.addMesButton}
          >
            + Agregar nuevo mes
          </button>
        </div>
      ))}

      {/* Botón para validar */}
      <div style={styles.validationBox}>
        <button
          type="button"
          onClick={() => {
            const errores = validarProgramacion();
            if (errores.length > 0) {
              alert('❌ Errores de validación:\n- ' + errores.join('\n- '));
            } else {
              alert('✅ Validación exitosa');
            }
          }}
          style={styles.validateButton}
        >
          Validar programación
        </button>
      </div>
    </div>
  );
};

